import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import orderService from '../services/orderService';

const CUSTOMER_ORDERS_CACHE_KEY = 'customer_orders_cache_v1';

const readCachedOrders = () => {
    try {
        const raw = localStorage.getItem(CUSTOMER_ORDERS_CACHE_KEY);
        if (!raw) {
            return null;
        }

        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') {
            return null;
        }

        return {
            orders: Array.isArray(parsed.orders) ? parsed.orders : [],
            pagination: parsed.pagination && typeof parsed.pagination === 'object' ? parsed.pagination : {},
        };
    } catch {
        return null;
    }
};

export default function Orders() {
    const { user } = useAuth();
    const cached = readCachedOrders();
    const [orders, setOrders] = useState(cached?.orders || []);
    const [loading, setLoading] = useState(!(cached?.orders?.length > 0));
    const [error, setError] = useState('');
    const [page, setPage] = useState(1);
    const [pagination, setPagination] = useState(cached?.pagination || {});

    useEffect(() => {
        loadOrders();
    }, [page]);

    const loadOrders = async () => {
        try {
            setLoading(true);
            setError('');
            const res = await orderService.getOrders(page);
            const rows = res?.data?.data?.data || [];
            const paging = res?.data?.data || {};

            setOrders(rows);
            setPagination(paging);

            localStorage.setItem(CUSTOMER_ORDERS_CACHE_KEY, JSON.stringify({
                orders: rows,
                pagination: paging,
            }));
        } catch (err) {
            if ((orders || []).length === 0) {
                setError('Unable to fetch your orders right now.');
            }
        } finally {
            setLoading(false);
        }
    };

    const getStatusBadge = (status) => {
        const statusColors = {
            processing: 'badge-warning',
            shipped: 'badge-info',
            delivered: 'badge-success',
            cancelled: 'badge-danger',
        };
        return `badge ${statusColors[status] || 'badge-secondary'}`;
    };

    if (loading && orders.length === 0) {
        return null;
    }

    return (
        <div className="orders-page">
            <div className="container">
                <div className="page-header">
                    <h1>My Orders</h1>
                    <p>View and track all your orders</p>
                </div>

                {error && <div className="alert alert-danger">{error}</div>}

                {orders.length === 0 ? (
                    <div className="empty-state">
                        <h2>No orders yet</h2>
                        <p>Start shopping to place your first order</p>
                        <Link to="/products" className="btn btn-primary">
                            Browse Products
                        </Link>
                    </div>
                ) : (
                    <>
                        <div className="orders-grid">
                            {orders.map((order) => (
                                <Link
                                    key={order.id}
                                    to={`/orders/${order.id}`}
                                    className="order-card"
                                >
                                    <div className="order-card-header">
                                        <div>
                                            <h3>Order #{order.order_number}</h3>
                                            <p className="order-date">
                                                {new Date(order.created_at).toLocaleDateString()}
                                            </p>
                                        </div>
                                        <div className={getStatusBadge(order.status)}>
                                            {order.status}
                                        </div>
                                    </div>

                                    <div className="order-card-body">
                                        <p className="item-count">
                                            {order.items.length} item{order.items.length !== 1 ? 's' : ''}
                                        </p>
                                        <p className="total-amount">
                                            Total: <strong>₱{order.total_amount.toFixed(2)}</strong>
                                        </p>
                                    </div>

                                    <div className="order-card-footer">
                                        <small>{order.payment_method.toUpperCase()} - {order.payment_status}</small>
                                    </div>
                                </Link>
                            ))}
                        </div>

                        {pagination.last_page > 1 && (
                            <div className="pagination">
                                <button
                                    onClick={() => setPage(page - 1)}
                                    disabled={page === 1}
                                    className="btn btn-sm"
                                >
                                    Previous
                                </button>
                                <span className="page-info">
                                    Page {page} of {pagination.last_page}
                                </span>
                                <button
                                    onClick={() => setPage(page + 1)}
                                    disabled={page === pagination.last_page}
                                    className="btn btn-sm"
                                >
                                    Next
                                </button>
                            </div>
                        )}
                    </>
                )}
            </div>
        </div>
    );
}
